import React from "react";
import TestimonialCard from "./TestimonialCard";

const cardExample = {
  title: "Frontend",
  text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
  role: "Desarrollador",
  backType: "list",
  backContent: [
    "Octavio Luna",
    "Leonardo Ibarra",
    "Leandro Colque",
    "Rodny Siles",
    "Kevin Sancalli",
    "Einar Guillen",
    "Huascar Duran",
    "Alejandro Zamorano",
  ],
};

const AboutUsContainer = () => {
  return (
    <main style={{ backgroundColor: "#f8f2e7", color: "#003E73", padding: "3rem 1rem" }}>
      <h2
        style={{
          fontSize: "1.3rem",
          fontWeight: "700",
          color: "#e4d0a9",
          marginBottom: "2rem",
          textAlign: "center",
        }}
      >
        LAS PERSONAS Y EQUIPOS QUE HICIERON POSIBLE
      </h2>
      <TestimonialCard card={cardExample} />
    </main>
  );
};

export default AboutUsContainer;
